-- ----------------------------
-- Table structure for purchases
-- ----------------------------
DROP TABLE IF EXISTS `purchases`;
CREATE TABLE `purchases`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键，自增',
  `book_id` bigint NOT NULL COMMENT '外键 → books.id',
  `quantity` int NOT NULL COMMENT '进货数量',
  `unit_price` decimal(10, 2) NOT NULL COMMENT '进货单价',
  `total_amount` decimal(10, 2) NOT NULL COMMENT '进货总额 = unit_price × quantity',
  `purchase_date` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '进货时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `fk_purchase_book`(`book_id` ASC) USING BTREE,
  CONSTRAINT `fk_purchase_book` FOREIGN KEY (`book_id`) REFERENCES `books` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 2002 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '进货表' ROW_FORMAT = Dynamic;

