-- ----------------------------
-- Table structure for sale_items
-- ----------------------------
DROP TABLE IF EXISTS `sale_items`;
CREATE TABLE `sale_items`  (
  `sale_id` bigint NOT NULL COMMENT '外键 → sales.id（ON DELETE CASCADE：删订单自动删明细）',
  `book_id` bigint NOT NULL COMMENT '外键 → books.id',
  `quantity` int NOT NULL COMMENT '购买数量',
  `unit_price` decimal(10, 2) NOT NULL COMMENT '销售单价（取自 books.price）',
  `unit_cost` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '销售成本（取自 books.cost_price）',
  `subtotal` decimal(10, 2) NOT NULL COMMENT '小计 = unit_price × quantity',
  PRIMARY KEY (`sale_id`, `book_id`) USING BTREE,
  INDEX `fk_saleitem_book`(`book_id` ASC) USING BTREE,
  CONSTRAINT `fk_saleitem_book` FOREIGN KEY (`book_id`) REFERENCES `books` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_saleitem_sale` FOREIGN KEY (`sale_id`) REFERENCES `sales` (`sale_id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '销售明细表' ROW_FORMAT = Dynamic;

