-- ----------------------------
-- Table structure for sales
-- ----------------------------
DROP TABLE IF EXISTS `sales`;
CREATE TABLE `sales`  (
  `sale_id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键，自增',
  `customer_id` bigint NULL DEFAULT NULL COMMENT '外键 → customers.id（可为空，散客）',
  `total_amount` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '订单总金额 = 所有明细 subtotal 之和',
  `total_cost` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '订单总成本 = 所有明细 unitCost×quantity 之和',
  `sale_date` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '销售时间',
  PRIMARY KEY (`sale_id`) USING BTREE,
  INDEX `fk_sale_customer`(`customer_id` ASC) USING BTREE,
  CONSTRAINT `fk_sale_customer` FOREIGN KEY (`customer_id`) REFERENCES `customers` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 2002 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '销售订单主表' ROW_FORMAT = Dynamic;

